using System;
using UnityEngine;
using UnityEngine.SceneManagement;

/// <summary>
/// Terra de Gaia (GDD "Abertura do Mapa"): liga o botão de Mapa
/// (<see cref="PlayerInputRouter.MapPressed"/>) à cena do Terra de Gaia.
///
/// GDD: "o mapa só abre nas entradas/saídas de área, não livremente" — por
/// omissão (<see cref="requireAccessZone"/> = true), só abre enquanto o
/// jogador estiver dentro de uma <see cref="WorldMapAccessZone"/> (colocada
/// nos pontos de entrada/saída de cada área).
///
/// Ao abrir, guarda a área actual (<see cref="WorldState.CurrentArea"/>) e
/// carrega a cena do Terra de Gaia (<see cref="mapSceneName"/>) com
/// <see cref="LoadingScreenController"/>. Na cena do mapa, subscreve
/// <see cref="WorldMapController.TravelRequested"/> (carrega a área escolhida)
/// e <see cref="WorldMapController.CancelRequested"/> (volta à área guardada).
///
/// Singleton com auto-fallback (mesmo padrão de <see cref="SceneLoader"/>) —
/// persiste entre cenas (DontDestroyOnLoad).
/// </summary>
public class WorldMapEntryPoint : MonoBehaviour
{
    public static WorldMapEntryPoint Instance { get; private set; }

    [Header("Cena do Terra de Gaia")]
    [Tooltip("Nome da cena do Terra de Gaia (tem de estar nas Build Settings).")]
    public string mapSceneName = "MapaMundi";

    [Header("Acesso")]
    [Tooltip("Se activo (recomendado pelo GDD), o botão de Mapa só abre o Terra de Gaia enquanto o jogador estiver dentro de uma WorldMapAccessZone. Se desactivado, o mapa abre em qualquer lugar.")]
    public bool requireAccessZone = true;

    [Header("Input")]
    [Tooltip("Router de input cujo evento MapPressed abre o Terra de Gaia. Se vazio, procura automaticamente um PlayerInputRouter na cena (incluindo objectos inactivos) sempre que uma cena carrega.")]
    public PlayerInputRouter inputRouter;

    private bool isAutoFallback;
    private bool insideAccessZone;
    private bool isMapOpen;
    private AreaData areaBeforeMap;

    // ==================================================================
    // Singleton (auto-fallback — mesmo padrão de SceneLoader)
    // ==================================================================

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;

        var go = new GameObject(nameof(WorldMapEntryPoint) + " (Fallback)");
        var instance = go.AddComponent<WorldMapEntryPoint>();
        instance.isAutoFallback = true;
    }

    private void OnEnable()
    {
        SceneManager.sceneLoaded += OnSceneLoaded;
        TryBindInput();
    }

    private void OnDisable()
    {
        SceneManager.sceneLoaded -= OnSceneLoaded;
        UnbindInput();
        UnsubscribeFromMap();
    }

    private void OnSceneLoaded(Scene scene, LoadSceneMode mode)
    {
        // Cada cena nova começa sem "acesso ao mapa" — uma WorldMapAccessZone
        // presente na cena (player já dentro dela ao carregar) regista-se de
        // novo via OnTriggerEnter2D no(s) primeiro(s) frame(s) de física.
        insideAccessZone = false;

        TryBindInput();

        if (isMapOpen)
        {
            // Cena recém-carregada é a do Terra de Gaia: liga-se ao "cérebro"
            // assim que ele existir (WorldMapController.Awake já correu antes
            // de LoadingScreenController chamar onLoaded).
            var controller = WorldMapController.Instance;
            if (controller != null)
            {
                controller.TravelRequested += HandleTravelRequested;
                controller.CancelRequested += HandleCancelRequested;
            }
        }
    }

    private void TryBindInput()
    {
        if (inputRouter == null)
            inputRouter = FindObjectOfType<PlayerInputRouter>(true);

        if (inputRouter != null)
        {
            inputRouter.MapPressed -= HandleMapPressed;
            inputRouter.MapPressed += HandleMapPressed;
        }
    }

    private void UnbindInput()
    {
        if (inputRouter != null) inputRouter.MapPressed -= HandleMapPressed;
    }

    // ==================================================================
    // Zona de Acesso (GDD: "abre apenas nas entradas/saídas de área")
    // ==================================================================

    /// <summary>Chamado por <see cref="WorldMapAccessZone"/> quando o jogador entra/sai de uma zona de acesso ao Terra de Gaia.</summary>
    public void SetInsideAccessZone(bool inside) => insideAccessZone = inside;

    // ==================================================================
    // Abrir / Fechar o Mapa
    // ==================================================================

    private void HandleMapPressed()
    {
        if (isMapOpen) return;
        if (requireAccessZone && !insideAccessZone) return;
        if (string.IsNullOrEmpty(mapSceneName)) return;
        if (SceneLoader.Instance != null && SceneLoader.Instance.IsLoading) return;

        areaBeforeMap = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;
        isMapOpen = true;

        if (LoadingScreenController.Instance != null)
            LoadingScreenController.Instance.LoadScene(mapSceneName, null);
        else
            Debug.LogWarning("[WorldMapEntryPoint] LoadingScreenController.Instance não encontrado — não é possível abrir o Terra de Gaia.");
    }

    private void HandleTravelRequested(AreaData area)
    {
        CloseMap();

        if (area != null && SceneLoader.Instance != null)
            SceneLoader.Instance.LoadArea(area);
    }

    private void HandleCancelRequested()
    {
        CloseMap();

        if (areaBeforeMap != null && SceneLoader.Instance != null)
            SceneLoader.Instance.LoadArea(areaBeforeMap);
    }

    private void CloseMap()
    {
        UnsubscribeFromMap();
        isMapOpen = false;
    }

    private void UnsubscribeFromMap()
    {
        var controller = WorldMapController.Instance;
        if (controller == null) return;

        controller.TravelRequested -= HandleTravelRequested;
        controller.CancelRequested -= HandleCancelRequested;
    }
}

/// <summary>
/// Terra de Gaia (GDD "Abertura do Mapa"): colocar nos pontos de entrada/saída de
/// cada área (Collider2D com "Is Trigger" activo). Enquanto o jogador estiver
/// dentro, <see cref="WorldMapEntryPoint"/> permite abrir o Terra de Gaia com o
/// botão de Mapa.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class WorldMapAccessZone : MonoBehaviour
{
    [Tooltip("Apenas para identificação no Inspector/depuração.")]
    public string zoneId;

    private void Reset()
    {
        var col = GetComponent<Collider2D>();
        if (col != null) col.isTrigger = true;
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        WorldMapEntryPoint.Instance?.SetInsideAccessZone(true);
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        WorldMapEntryPoint.Instance?.SetInsideAccessZone(false);
    }
}
